const item = $input.first().json;
const raw = item.text ?? item.response ?? item.output ?? JSON.stringify(item);
const text = typeof raw === 'string' ? raw : JSON.stringify(raw);

const start = text.indexOf('{');
const end = text.lastIndexOf('}');
if (start === -1 || end === -1) {
  throw new Error('LLM did not return JSON. Raw: ' + text.slice(0, 400));
}

const parsed = JSON.parse(text.slice(start, end + 1));
const clamp = (n) => Math.max(0, Math.min(100, Number(n) || 0));
const score = clamp(parsed.overall_score);

return [{
  json: {
    candidate_name: parsed.candidate_name || $('Build Evaluation Context').item.json.candidate_name,
    overall_score: score,
    technical_match: clamp(parsed.technical_match),
    experience_match: clamp(parsed.experience_match),
    leadership_match: clamp(parsed.leadership_match),
    strengths: Array.isArray(parsed.strengths) ? parsed.strengths : [],
    gaps: Array.isArray(parsed.gaps) ? parsed.gaps : [],
    recommendation: parsed.recommendation || '',
    interview_priority: ['HIGH', 'MEDIUM', 'LOW'].includes(parsed.interview_priority)
      ? parsed.interview_priority
      : (score >= 80 ? 'HIGH' : score >= 60 ? 'MEDIUM' : 'LOW')
  }
}];

const jobTitle = $('Load Demo Screening Batch').first().json.job_title;
const payload = $input.first().json;
const rows = Array.isArray(payload.data) ? payload.data : $input.all().map((i) => i.json);

const ranking = [...rows]
  .sort((a, b) => (b.overall_score || 0) - (a.overall_score || 0))
  .map((c, idx) => ({ rank: idx + 1, ...c }));

return [{
  json: {
    product: 'AI Talent Copilot',
    workflow: '07 - Recruiter Screening Engine',
    job_title: jobTitle,
    candidates_evaluated: ranking.length,
    ranking
  }
}];
